attributes.cssVariables:
:root {
  --background: #ece9e1;
  --foreground: #16161c;
  --card: #ffffff;
  --card-foreground: #16161c;
  --popover: #ffffff;
  --popover-foreground: #16161c;
  --primary: #00ffba;
  --primary-foreground: #04231a;
  --secondary: #f1eee6;
  --secondary-foreground: #16161c;
  --muted: #f0ede4;
  --muted-foreground: #8a8578;
  --accent: #16e098;
  --accent-foreground: #04231a;
  --destructive: #ff5f57;
  --destructive-foreground: #ffffff;
  --border: #ddd8cb;
  --input: #ffffff;
  --ring: #16e098;
  --chart-1: #ff5b9c;
  --chart-2: #2bb3ff;
  --chart-3: #7b5bff;
  --chart-4: #c2e23f;
  --chart-5: #ff9d3d;
  --sidebar: #f0ede4;
  --sidebar-foreground: #16161c;
  --sidebar-primary: #11cf8a;
  --sidebar-primary-foreground: #04231a;
  --sidebar-accent: #16e098;
  --sidebar-accent-foreground: #04231a;
  --sidebar-border: #ddd8cb;
  --sidebar-ring: #16e098;
  --font-sans: 'IBM Plex Sans', 'Helvetica Neue', Arial, ui-sans-serif, sans-serif, system-ui;
  --font-serif: 'IBM Plex Serif', 'Georgia', Times, serif;
  --font-mono: 'IBM Plex Mono', 'Menlo', 'Courier New', Courier, ui-monospace, monospace;
  --radius: 1rem;
  --shadow-color: #000000;
  --shadow-2xs: 0 1px 0 #e4e0d4;
  --shadow-xs: 0 1px 0 #e4e0d4;
  --shadow-sm: 0 1px 0 #e4e0d4, 0 14px 30px -22px rgba(0, 0, 0, 0.4);
  --shadow: 0 1px 0 #e4e0d4, 0 14px 30px -22px rgba(0, 0, 0, 0.4);
  --shadow-md: 0 1px 0 #e4e0d4, 0 18px 40px -26px rgba(0, 0, 0, 0.4);
  --shadow-lg: 0 1px 0 #e4e0d4, 0 26px 44px -22px rgba(0, 0, 0, 0.45);
  --shadow-xl: 0 1px 0 #e4e0d4, 0 30px 70px -24px rgba(0, 0, 0, 0.4);
  --shadow-2xl: 0 1px 0 #e4e0d4, 0 40px 80px -28px rgba(0, 0, 0, 0.46);
  --tracking-normal: 0.01em;
  --spacing: 0.25rem;
}
